<template>
  <VContainer fluid>
    <VRow>
      <VCol cols="6">
        <VAutocomplete
          ref="autocomplete"
          v-model="selectedBarang"
          v-model:search="searchTerm"
          :items="filteredItems"
          autofocus
          combobox
          item-title="nama"
          label="Cari Barang"
          return-object
          @keyup="onKeyup"
          @update:focused="onFocused"
          @update:model-value="
            () => {
              updateHarga()
            }
          "
        >
        </VAutocomplete>
      </VCol>
      <VCol cols="1">
        <VTextField
          ref="quantityInput"
          v-model.number="quantity"
          label="Jumlah"
          type="number"
          @keyup.enter="tambahBarang"
        ></VTextField>
      </VCol>
      <VCol cols="2">
        <VTextField v-model="hargaSatuan" label="Harga Satuan" readonly></VTextField>
      </VCol>
      <VCol cols="2">
        <VTextField v-model="subtotal" label="Subtotal" readonly></VTextField>
      </VCol>
      <VCol cols="1">
        <VBtn @click="tambahBarang">Tambah</VBtn>
      </VCol>
    </VRow>
    <VRow>
      <VCol cols="12">
        <VDataTable :headers="headers" :items="keranjang">
          <template v-slot:item.id="{ item }">
            <VBtn size="x-small" @click="hapusBarang(item.columns.id)">del</VBtn>
          </template>
          <template v-slot:item.quantity="{ item }">
            <VTextField
              control-variant="split"
              type="number"
              v-model.number="item.columns.quantity"
              @update:model-value="(newQty) => onQtyChange(newQty, item.columns.id)"
            >
            </VTextField>
          </template>
          <template v-slot:item.subtotal="{ item }">
            {{ item.columns.quantity * item.columns.hargaSatuan }}
          </template>
        </VDataTable>
      </VCol>
      <VCol cols="12">
        <PaymentForm
          :items="keranjang"
          :show="showPayment"
          :total="payment"
          @onHide="onHidePayment"
        />
      </VCol>
      <!-- <VCol cols="12"> {{ keranjang }}</VCol> -->
    </VRow>

    <VRow justify="end">
      <VCol cols="4">
        <VTextField v-model="total" label="Total" readonly></VTextField>
      </VCol>
    </VRow>
    <VRow justify="end">
      <VCol cols="2">
        <VBtn color="primary" @click="bayar">Bayar </VBtn>
      </VCol>
    </VRow>
  </VContainer>
</template>
<script setup>
import { forEach } from 'lodash-es'
import { ref, computed, watch, onMounted, nextTick } from 'vue'
// import TableData from '@/@core/components/table-data/TableData.vue'
import { VDataTable } from 'vuetify/labs/VDataTable'
import PaymentForm from './PaymentForm.vue'
import { useAppStore } from '@/stores/appStore'

const autocomplete = ref(null)
const quantityInput = ref(null)
const { axiosGet } = useAppStore()

const daftarBarang = ref([
  { id: 1, nama: 'Indomie Goreng', harga: 3000 },
  { id: 2, nama: 'Aqua 600ml', harga: 3500 },
  { id: 3, nama: 'Sabun Mandi Lux', harga: 5000 }
])
const selectedBarang = ref(null)
const quantity = ref(1)
const hargaSatuan = ref(0)
const keranjang = ref([])
const showPayment = ref(false)

const payment = ref(0)

const headers = ref([
  { title: 'Nama Barang', key: 'nama' },
  { title: 'Jumlah', key: 'quantity', align: 'end', width: '100' },
  { title: 'Harga Satuan', key: 'hargaSatuan', align: 'end' },
  { title: 'Subtotal', key: 'subtotal', align: 'end' },
  { title: 'Actions', key: 'id', sortable: false, align: 'end' }
])

const searchTerm = ref('')

const total = ref(0)
const subtotal = computed(() => hargaSatuan.value * quantity.value)

const filteredItems = computed(() => {
  const query = searchTerm.value ? searchTerm.value.trim() : ''
  if (!query) return []

  // First, try for an exact match on barcode, name or ID (for barcode scanner)
  const exactMatch = daftarBarang.value.find(
    (barang) =>
      barang.barcode === query ||
      barang.nama.toLowerCase() === query.toLowerCase() ||
      String(barang.id) === query
  )
  if (exactMatch) {
    return [exactMatch]
  }

  // If no exact match, perform a contains search for manual typing, if query is long enough
  if (query.length < 2) {
    return []
  }
  const results = daftarBarang.value.filter((barang) =>
    barang.nama.toLowerCase().includes(query.toLowerCase())
  )
  return results
})

const onFocused = (focused) => {
  if (!focused) {
    // searchTerm.value = ''
  }
}

const onKeyup = (event) => {
  if (event.key === 'Enter') {
    // If no item is selected and the search returns a single result (likely a barcode scan)
    console.log('Enter pressed')
    if (!selectedBarang.value && filteredItems.value.length === 1) {
      selectedBarang.value = filteredItems.value[0]
      updateHarga() // Manually trigger price update
      nextTick(() => {
        quantityInput.value.focus()
      })
    }
    // tambahBarang()
  }
}
function updateHarga() {
  if (selectedBarang.value) {
    console.log('Updating price for', selectedBarang.value.nama)
    hargaSatuan.value = selectedBarang.value.harga
    nextTick(() => {
      quantityInput.value.focus()
    })
  } else {
    hargaSatuan.value = 0
  }
}

function tambahBarang() {
  console.log(selectedBarang.value)
  if (selectedBarang.value) {
    var index = -1
    for (let i = 0; i < keranjang.value.length; i++) {
      if (keranjang.value[i].id === selectedBarang.value.id) {
        index = i
        break
      }
    }
    if (index !== -1) {
      keranjang.value[index].quantity += quantity.value
    } else {
      keranjang.value.push({
        id: selectedBarang.value.id,
        nama: selectedBarang.value.nama,
        quantity: quantity.value,
        hargaSatuan: hargaSatuan.value
      })
    }
    selectedBarang.value = null
    quantity.value = 1
    hargaSatuan.value = 0
    searchTerm.value = ''

    nextTick(() => {
      autocomplete.value.focus()
    })
  }
}

function hapusBarang(itemId) {
  const index = keranjang.value.findIndex((i) => i.id === itemId)
  console.log(index)
  if (index !== -1) {
    keranjang.value.splice(index, 1)
  }
}

function bayar() {
  if (keranjang.value.length === 0) {
    alert('Keranjang kosong!')
    return
  }
  payment.value = total.value
  showPayment.value = true
}

function onHidePayment(e) {
  showPayment.value = false
  switch (e.status) {
    case 'paid':
      keranjang.value = []
      total.value = 0
      break
    case 'hide':
      break
    default:
      break
  }
}

const onQtyChange = (newQty, itemId) => {
  const index = keranjang.value.findIndex((i) => i.id === itemId)
  if (index !== -1) {
    keranjang.value[index].quantity = newQty
  }
}

// const onQtyChange = (a, b) => {
//   console.log(a, b)
// }

watch(
  keranjang,
  (newValue) => {
    let newTotal = 0
    newValue.forEach((item) => {
      newTotal += item.quantity * item.hargaSatuan
    })
    total.value = newTotal
  },
  { deep: true }
)

// watch(quantity, () => {
//   subtotal.value = hargaSatuan.value * quantity.value
// })

onMounted(() => {
  axiosGet('/barang').then((res) => {
    // console.log(res)
    if (res.status == 200) {
      const a = []
      forEach(res.data, (b) => {
        a.push({ id: b.id, nama: b.nama, harga: b.hargaJual, barcode: b.barcode })
      })
      daftarBarang.value = a
    }
  })
})
</script>
